import React from "react";
import { useParams } from "react-router-dom"; // For accessing the URL params.
import "../styles/NewsDetail.css"; // Create the appropriate CSS for details page.

const newsData = [
  {
    id: 1,
    img: "/images/news1.jpg",
    title: "Legal Insights on Intellectual Property",
    description:
      "Stay updated with the latest trends and challenges in intellectual property law.",
    fullDescription:
      "In this article, we discuss the complexities of intellectual property law, including the most common pitfalls, how businesses can safeguard their IP, and the potential legal issues they might face when dealing with international IP laws.",
  },
  {
    id: 2,
    img: "/images/news2.jpg",
    title: "Bankruptcy Law and Its Impact on Corporations",
    description:
      "How does bankruptcy law affect the financial stability of businesses? Read about the legal procedures and implications for corporations during bankruptcy.",
    fullDescription:
      "Bankruptcy law is designed to protect creditors and ensure that debts are paid, but it also has significant impacts on corporations and their employees.",
  },
  {
    id: 3,
    img: "/images/news3.jpg",
    title: "Corporate Mergers: Legal Framework and Challenges",
    description:
      "Mergers and acquisitions are complex processes. In this article, we outline the legal frameworks involved and highlight some of the challenges businesses face during mergers.",
    fullDescription:
      "Mergers and acquisitions (M&A) can be a growth strategy for many businesses, but they come with significant legal hurdles. From regulatory approvals to contractual obligations, this article covers the essential aspects businesses need to consider when undertaking M&A activities.",
  },
];

const NewsDetail = () => {
  const { id } = useParams();
  const news = newsData.find((newsItem) => newsItem.id === parseInt(id));

  return (
    <div className="news-detail">
      <h1>{news.title}</h1>
      <img src={news.img} alt={news.title} />
      <p>{news.fullDescription}</p>
    </div>
  );
};

export default NewsDetail;
